1	export class GameOfLife {
2	  private cells: [number, number][] = [];
3	
4	  getCells() {
5	    return this.cells;
6	  }
7	
8	  addCell(x: number, y: number) {
9	    this.cells.push([x, y]);
10	  }
11	
12	  private isCellAlive(x: number, y: number): boolean {
13	    return this.cells.some(cell => cell[0] === x && cell[1] === y);
14	  }
15	
16	  countNeighbors(x: number, y: number): number {
17	    let count = 0;
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        if (this.isCellAlive(x + dx, y + dy)) {
22	          count++;
23	        }
24	      }
25	    }
26	    return count;
27	  }
28	
29	  nextGeneration(): [number, number][] {
30	    const survivors: [number, number][] = [];
31	    for (const [x, y] of this.cells) {
32	      const neighbors = this.countNeighbors(x, y);
33	      if (neighbors === 2) {
34	        survivors.push([x, y]);
35	        break;
36	      }
37	    }
38	    return survivors;
39	  }
40	}
