nextGeneration(): [number, number][] {
  const survivors: [number, number][] = [];
  for (const [x, y] of this.cells) {
    const neighbors = this.countNeighbors(x, y);
    if (neighbors === 2 || neighbors === 3) {
      survivors.push([x, y]);
      break;
    }
  }
  return survivors;
}
